-- ── Résumé ────────────────────────────────────────────────────────────────────
SELECT 'vehicles' as table_name, count(*) FROM fleet.vehicles
UNION ALL SELECT 'trips', count(*) FROM fleet.trips
UNION ALL SELECT 'incidents', count(*) FROM fleet.incidents
UNION ALL SELECT 'maintenances', count(*) FROM fleet.maintenances
UNION ALL SELECT 'fuel_recharges', count(*) FROM fleet.fuel_recharges
UNION ALL SELECT 'expenses', count(*) FROM fleet.expenses
UNION ALL SELECT 'budgets', count(*) FROM fleet.budgets
UNION ALL SELECT 'schedules', count(*) FROM fleet.schedules
UNION ALL SELECT 'assignments', count(*) FROM fleet.assignments
UNION ALL SELECT 'drivers', count(*) FROM fleet.drivers
ORDER BY 1;
